use CGI;
use strict;

my $cgi = CGI->new();
my $filename = $cgi->param('logfile');
my $log_dir = '/path/to/log/directory';

open(FH, "$log_dir/$filename") or die "Cannot open file: $!";

print $cgi->header('text/html');
print "<pre>";

while (my $line = <FH>) {
    print $line;
}

close(FH);

print "</pre>";
print "</body></html>";
